SELECT "created_by_account_organizations"."id", COALESCE( ( SELECT JSONB_AGG(elem ) FROM (SELECT JSONB_BUILD_OBJECT('id', "created_by"."id", 'first_name', "created_by"."first_name", 'last_name', "created_by"."last_name", 'created_by_full_name', (COALESCE("created_by"."first_name", '') || ' ' || COALESCE("created_by"."last_name", ''))) AS elem FROM contacts created_by WHERE (created_by.tombstone = 0) AND "created_by_account_organizations"."contact_id" = "created_by"."id") sub ), '[]' ) AS created_by, "updated_by_account_organizations"."id", COALESCE( ( SELECT JSONB_AGG(elem ) FROM (SELECT JSONB_BUILD_OBJECT('id', "updated_by"."id", 'first_name', "updated_by"."first_name", 'last_name', "updated_by"."last_name", 'updated_by_full_name', (COALESCE("updated_by"."first_name", '') || ' ' || COALESCE("updated_by"."last_name", ''))) AS elem FROM contacts updated_by WHERE (updated_by.tombstone = 0) AND "updated_by_account_organizations"."contact_id" = "updated_by"."id") sub ), '[]' ) AS updated_by FROM contacts LEFT JOIN LATERAL (SELECT "joined_created_by_account_organizations"."id" FROM "account_organizations" "joined_created_by_account_organizations" WHERE (joined_created_by_account_organizations.tombstone = 0) AND "joined_created_by_account_organizations"."id" = "contacts"."created_by" ) AS "created_by_account_organizations" ON TRUE LEFT JOIN LATERAL (SELECT "joined_created_by"."id", "joined_created_by"."first_name", "joined_created_by"."last_name" FROM "contacts" "joined_created_by" WHERE (joined_created_by.tombstone = 0) AND "joined_created_by"."id" = "created_by_account_organizations"."contact_id" ) AS "created_by" ON TRUE LEFT JOIN LATERAL (SELECT "joined_updated_by_account_organizations"."id" FROM "account_organizations" "joined_updated_by_account_organizations" WHERE (joined_updated_by_account_organizations.tombstone = 0) AND "joined_updated_by_account_organizations"."id" = "contacts"."updated_by" ) AS "updated_by_account_organizations" ON TRUE LEFT JOIN LATERAL (SELECT "joined_updated_by"."id", "joined_updated_by"."first_name", "joined_updated_by"."last_name" FROM "contacts" "joined_updated_by" WHERE (joined_updated_by.tombstone = 0) AND "joined_updated_by"."id" = "updated_by_account_organizations"."contact_id" ) AS "updated_by" ON TRUE WHERE (contacts.tombstone = 0) AND contacts.status::text = 'Active' ORDER BY LOWER(contacts.id) ASC LIMIT 100